import 'package:flutter/material.dart';import '../../services/migration_status_service.dart';class MigrationStatusPage extends StatelessWidget{MigrationStatusPage({super.key});final status=MigrationStatusService().calculate(currentVersion:3,latestVersion:5);@override Widget build(BuildContext context)=>Scaffold(appBar:AppBar(title:const Text('Migrations')),body:ListView(padding:const EdgeInsets.all(16),children:[Card(child:ListTile(leading:Icon(status.isUpToDate?Icons.check_circle_outline:Icons.pending_actions_outlined),title:Text(status.isUpToDate?'Database is up to date':'Pending migrations'),subtitle:Text('Current: ${status.currentVersion} · Latest: ${status.latestVersion}'))),...status.pendingVersions.map((v)=>Card(child:ListTile(leading:const Icon(Icons.storage_outlined),title:Text('Migration v$v'),subtitle:const Text('Pending placeholder'))))]));}
